import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjDiagram } from "./OjDiagram";
export { OjDiagram };

/**
 * Create an instance of [[OjDiagram]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojDiagram(driver, By.id('my-oj-diagram'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojDiagram(driver: DriverLike, by: By): Promise<OjDiagram> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjDiagram
  if (!(webEl instanceof OjDiagram)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-diagram>`);
  }
  return webEl;
}

register("oj-diagram", OjDiagram);
